// src/pages/Donate.js
import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { loadStripe } from '@stripe/stripe-js';
import { Elements, CardElement, useStripe, useElements } from '@stripe/react-stripe-js';
import './Home.css';
import './Payment.css';

// Initialize Stripe outside the component
const stripePromise = loadStripe('pk_test_51RFfpPI7FWu561A0WglXKU8G05G51nieOuNPj4YR2CXvoLocst2D7jFcrP4hcqC670uo4ZNB7y1DB6WvaQ1HrP1400LCZS6PZD');

const PaymentForm = ({ amount }) => {
  const stripe = useStripe();
  const elements = useElements();
  const [error, setError] = useState(null);
  const [processing, setProcessing] = useState(false);
  const [succeeded, setSucceeded] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (event) => {
    event.preventDefault();
    setProcessing(true);

    if (!stripe || !elements) {
      return;
    }

    try {
      const { error, paymentMethod } = await stripe.createPaymentMethod({
        type: 'card',
        card: elements.getElement(CardElement),
      });

      if (error) {
        setError(error.message);
        setProcessing(false);
        return;
      }

      // Send payment information to your backend
      const response = await fetch('/api/payment', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          paymentMethodId: paymentMethod.id,
          amount: amount * 100, // Convert to cents
        }),
      });

      const result = await response.json();

      if (result.success) {
        setSucceeded(true);
        setError(null);
        setProcessing(false);
        // Redirect to success page or show success message
        navigate('/payment-success');
      } else {
        setError(result.error);
        setProcessing(false);
      }
    } catch (err) {
      setError('An error occurred while processing your payment.');
      setProcessing(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="payment-form">
      <div className="form-group">
        <label>Card Details</label>
        <CardElement
          options={{
            style: {
              base: {
                fontSize: '16px',
                color: '#424770',
                '::placeholder': {
                  color: '#aab7c4',
                },
              },
              invalid: {
                color: '#9e2146',
              },
            },
          }}
        />
      </div>
      {error && <div className="error-message">{error}</div>}
      <button
        type="submit"
        className="payment-button"
        disabled={!stripe || processing || succeeded}
      >
        {processing ? 'Processing...' : `Pay $${amount}`}
      </button>
    </form>
  );
};

const Payment = () => {
  const location = useLocation();
  const [amount, setAmount] = useState(0);

  useEffect(() => {
    if (location.state && location.state.amount) {
      setAmount(location.state.amount);
    }
  }, [location]);

  return (
    <div className="paymentpage">
      <div className="donate">
        <h2>Complete Your Donation</h2>
        <p>Thank you for supporting wildlife conservation. Please enter your payment details below.</p>
        <Elements stripe={stripePromise}>
          <PaymentForm amount={amount} />
        </Elements>
      </div>
    </div>
  );
};

export default Payment;
